import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { MapContainer, TileLayer, Marker, Popup, useMap, LayerGroup } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet.heat';
import 'leaflet/dist/leaflet.css';
import { Eye, EyeOff } from 'lucide-react';

const HeatmapLayer = ({ points, name }) => {
  const map = useMap();
  useEffect(() => {
    if (!map || !points.length) return;
    const heat = L.heatLayer(points, { 
      radius: 30, 
      blur: 20, 
      maxZoom: 12,
      gradient: { 0.2: 'blue', 0.4: 'cyan', 0.6: 'lime', 0.8: 'yellow', 1.0: 'red' }
    }).addTo(map);
    return () => map.removeLayer(heat);
  }, [map, points]);
  return null;
};

const PollutionMap = () => {
  const [predictions, setPredictions] = useState([]);
  const [pollutionData, setPollutionData] = useState([]);
  const [selectedType, setSelectedType] = useState('AIR_QUALITY');
  const [visibleLayers, setVisibleLayers] = useState({
    AIR_QUALITY: true,
    WATER_QUALITY: true,
    NOISE_LEVEL: true,
    SOIL_POLLUTION: true
  });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchPredictions();
    fetchPollutionData();
  }, []);

  const fetchPredictions = async () => {
    try {
      setLoading(true);
      const response = await axios.get('http://localhost:8080/api/predictions/type/AIR_QUALITY');
      setPredictions(response.data || []);
    } catch (error) {
      console.error('Error fetching predictions:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchPollutionData = async () => {
    try {
      const response = await axios.get('http://localhost:8080/api/pollution-data/type/AIR_QUALITY');
      setPollutionData(response.data || []);
    } catch (error) {
      console.error('Error fetching pollution data:', error);
    }
  };

  const getPollutionColor = (level) => {
    const colorMap = {
      'GOOD': '#00ff00',
      'MODERATE': '#ffff00',
      'POOR': '#ff8800',
      'SEVERE': '#ff0000',
      'CRITICAL': '#8b0000'
    };
    return colorMap[level] || '#999';
  };

  const toggleLayer = (type) => {
    setVisibleLayers(prev => ({
      ...prev,
      [type]: !prev[type]
    }));
  };

  const mapPoints = predictions
    .filter(p => visibleLayers[p.pollutionType])
    .map(p => {
      const intensity = {
        'GOOD': 0.2,
        'MODERATE': 0.4,
        'POOR': 0.6,
        'SEVERE': 0.8,
        'CRITICAL': 1.0
      }[p.pollutionLevel] || 0.5;
      return [p.latitude, p.longitude, intensity];
    });

  return (
    <div style={{ display: 'flex', height: '100vh' }}>
      <aside style={{ 
        width: '280px', 
        backgroundColor: '#f5f5f5', 
        padding: '20px', 
        overflowY: 'auto',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
      }}>
        <h2 style={{ marginTop: 0 }}>Pollution Layers</h2>
        
        <div style={{ marginBottom: '20px' }}>
          <h4>Toggle Layers:</h4>
          {Object.keys(visibleLayers).map(type => (
            <div key={type} style={{ 
              display: 'flex', 
              alignItems: 'center', 
              gap: '10px', 
              marginBottom: '10px',
              padding: '8px',
              backgroundColor: visibleLayers[type] ? '#e3f2fd' : '#f0f0f0',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
            onClick={() => toggleLayer(type)}>
              {visibleLayers[type] ? <Eye size={18} /> : <EyeOff size={18} />}
              <span>{type.replace(/_/g, ' ')}</span>
            </div>
          ))}
        </div>

        <hr />

        <h4>Pollution Levels:</h4>
        <div style={{ marginBottom: '20px' }}>
          {Object.entries(getPollutionColor).map(([level, color]) => (
            <div key={level} style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '8px' }}>
              <div style={{ width: '20px', height: '20px', backgroundColor: color, borderRadius: '3px' }}></div>
              <span>{level}</span>
            </div>
          ))}
        </div>

        <hr />

        <h4>Recent Predictions:</h4>
        <div style={{ maxHeight: '300px', overflowY: 'auto' }}>
          {predictions.slice(0, 10).map(pred => (
            <div key={pred.id} style={{ 
              marginBottom: '10px', 
              padding: '10px',
              backgroundColor: '#fff',
              border: `2px solid ${getPollutionColor(pred.pollutionLevel)}`,
              borderRadius: '4px'
            }}>
              <strong style={{ color: getPollutionColor(pred.pollutionLevel) }}>
                {pred.value}
              </strong>
              <p style={{ margin: '5px 0 0 0', fontSize: '0.85rem' }}>
                {pred.location}
              </p>
              <small style={{ color: '#666' }}>
                Level: {pred.pollutionLevel}
              </small>
              {pred.trend && (
                <p style={{ margin: '3px 0 0 0', fontSize: '0.8rem', color: pred.trend === 'WORSENING' ? '#d32f2f' : '#4caf50' }}>
                  {pred.trend === 'WORSENING' ? '↑' : pred.trend === 'IMPROVING' ? '↓' : '→'} {pred.trend}
                </p>
              )}
            </div>
          ))}
        </div>
      </aside>

      <div style={{ flex: 1 }}>
        <MapContainer 
          center={[20.5937, 78.9629]} 
          zoom={5} 
          style={{ height: '100%', width: '100%' }}
        >
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; OpenStreetMap contributors'
          />
          {mapPoints.length > 0 && <HeatmapLayer points={mapPoints} name="Pollution Heatmap" />}
          
          {predictions.map(pred => (
            visibleLayers[pred.pollutionType] && (
              <Marker 
                key={pred.id} 
                position={[pred.latitude, pred.longitude]}
                icon={L.icon({
                  iconUrl: `data:image/svg+xml;base64,${btoa(`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${getPollutionColor(pred.pollutionLevel)}"><circle cx="12" cy="12" r="10"/></svg>`)}`,
                  iconSize: [25, 25],
                  iconAnchor: [12, 12]
                })}
              >
                <Popup>
                  <div>
                    <strong>{pred.pollutionType.replace(/_/g, ' ')}</strong><br/>
                    Value: {pred.value}<br/>
                    Level: <span style={{ color: getPollutionColor(pred.pollutionLevel), fontWeight: 'bold' }}>
                      {pred.pollutionLevel}
                    </span><br/>
                    Trend: {pred.trend}<br/>
                    Confidence: {pred.confidencePercentage}%<br/>
                    Location: {pred.location}
                  </div>
                </Popup>
              </Marker>
            )
          ))}
        </MapContainer>
      </div>
    </div>
  );
};

export default PollutionMap;
